const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;

const job_id = body.job_id || null;
const status = body.status || 'unknown';
const result = body.result ?? null;
const error = body.error ?? null;
const duration_ms = typeof body.duration_ms === 'number' ? body.duration_ms : null;
const completed_at = body.completed_at || new Date().toISOString();

const truncate = (value, max = 500) => {
  if (value === null || value === undefined) return null;
  const text = typeof value === 'string' ? value : JSON.stringify(value);
  return text.length > max ? `${text.slice(0, max)}...` : text;
};

const summaryText = status === 'completed'
  ? truncate(result, 400) || 'Completed without payload'
  : truncate(error, 400) || 'Failed without error payload';

const blockKit = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `Opencode Agent ${status.toUpperCase()}`
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Job ID:*\n${job_id || 'unknown'}` },
      { type: 'mrkdwn', text: `*Status:*\n${status}` },
      { type: 'mrkdwn', text: `*Duration:*\n${duration_ms !== null ? `${duration_ms}ms` : 'n/a'}` },
      { type: 'mrkdwn', text: `*Completed:*\n${completed_at}` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Summary:*\n\`\`\`${summaryText || 'n/a'}\`\`\``
    }
  }
];

console.log('opencode-agent callback received', {
  job_id,
  status,
  duration_ms,
  completed_at,
});

return {
  job_id,
  status,
  result,
  error,
  duration_ms,
  completed_at,
  blockKit,
  channel: 'opencode-agent',
  command: 'dispatch-callback',
  duration: duration_ms !== null ? Math.round(duration_ms / 1000) : null,
  errorMessage: truncate(error, 500),
  isSuccess: status === 'completed',
  source: 'opencode-agent',
  outputUrl: null,
  timedOut: status === 'timeout',
  pollCount: null,
};
